float readLineSensor() {
    unsigned long start_time, timeout = 3000; 
    float sensor_read[NUMBER_OF_LS_PINS] = {0, 0, 0, 0, 0};
    int remaining = NUMBER_OF_LS_PINS; 

    for (int light_sensor = 0; light_sensor < NUMBER_OF_LS_PINS; light_sensor++){   
        charge_Capacitor(light_sensor_list, light_sensor); 
    }

    start_time = micros(); 

    while(remaining > 0) {
        unsigned long current_time = micros(); 
        unsigned long elapsed_time = current_time - start_time; 

        for(int light_sensor = 0; light_sensor < NUMBER_OF_LS_PINS; light_sensor++){
            if(digitalRead(light_sensor_list[light_sensor]) == LOW){    
                if(sensor_read[light_sensor] == 0){            
                    sensor_read[light_sensor] = elapsed_time;            
                    remaining -= 1;
                }
            }
        }

        if(elapsed_time >= timeout){
            remaining = 0;
        }
    }

    if(sensor_read[2] > 1500 && sensor_read[1] < 1000 && sensor_read[3] < 1000){ 
        return 0.09; 
    }

    float Sensor_Summation = 0;

    for(int light_sensor = 0; light_sensor < NUMBER_OF_LS_PINS; light_sensor++){
        Sensor_Summation += sensor_read[light_sensor];
    }

    for(int light_sensor = 0; light_sensor < NUMBER_OF_LS_PINS; light_sensor++){
        sensor_read[light_sensor] /= Sensor_Summation;
    }

    float e_line = (sensor_read[0] + sensor_read[1] - sensor_read[3] - sensor_read[4]);
    return e_line; 
}

